'use client'

import { useCallback, useMemo, type ReactNode } from 'react'

import { RoomAudioRenderer, SessionProvider } from '@livekit/components-react'

import { useSpatialRealAvatar } from '../../hooks/useSpatialRealAvatar'
import type {
  UseSpatialRealAvatarOptions,
  UseSpatialRealAvatarSessionOptions,
} from '../../types/spatialreal-avatar'
import { SpatialRealAvatarContext } from './spatialreal-avatar-context'

export interface SpatialRealAvatarProviderProps
  extends UseSpatialRealAvatarOptions,
    UseSpatialRealAvatarSessionOptions {
  children: ReactNode
  muted?: boolean
  volume?: number
}

export function SpatialRealAvatarProvider({
  children,
  muted,
  onDisconnect,
  volume,
  ...options
}: SpatialRealAvatarProviderProps) {
  const avatar = useSpatialRealAvatar(options)
  const end = useCallback(async () => {
    try {
      await avatar.disconnect()
    } finally {
      onDisconnect?.()
    }
  }, [avatar, onDisconnect])

  const session = useMemo(
    () => ({
      ...avatar.session,
      end,
    }),
    [avatar.session, end],
  )

  const value = useMemo(
    () => ({
      ...avatar,
      session,
    }),
    [avatar, session],
  )

  return (
    <SpatialRealAvatarContext.Provider value={value}>
      <SessionProvider session={session}>
        <RoomAudioRenderer room={session.room} muted={muted} volume={volume} />
        {children}
      </SessionProvider>
    </SpatialRealAvatarContext.Provider>
  )
}

import { createContext, useContext } from 'react'

import type { UseSpatialRealAvatarResult } from '../../types/spatialreal-avatar'

export const SpatialRealAvatarContext = createContext<UseSpatialRealAvatarResult | null>(null)

export function useSpatialRealAvatarContext() {
  const context = useContext(SpatialRealAvatarContext)

  if (!context) {
    throw new Error('useSpatialRealAvatarContext must be used within SpatialRealAvatarProvider.')
  }

  return context
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'

import { useSession } from '@livekit/components-react'
import {
  AvatarManager,
  AvatarSDK,
  AvatarView,
  DrivingServiceMode,
  Environment,
  LoadProgress,
} from '@spatialwalk/avatarkit'
import { AvatarPlayer, LiveKitProvider } from '@spatialwalk/avatarkit-rtc'
import { TokenSource, Track } from 'livekit-client'
import type { Room } from 'livekit-client'

import type {
  SpatialRealAvatarState,
  SpatialRealAvatarConnectionStatus,
  UseSpatialRealAvatarOptions,
  UseSpatialRealAvatarResult,
} from '../types/spatialreal-avatar'

function toError(error: unknown, fallbackMessage: string) {
  return error instanceof Error ? error : new Error(fallbackMessage)
}

function sameSdkConfiguration(options: UseSpatialRealAvatarOptions) {
  const configuration = AvatarSDK.configuration

  return (
    AvatarSDK.appId === options.appId &&
    configuration?.environment === (options.environment ?? Environment.intl) &&
    configuration?.drivingServiceMode ===
      (options.drivingServiceMode ?? DrivingServiceMode.host) &&
    configuration?.characterApiBaseUrl === options.characterApiBaseUrl &&
    configuration?.logLevel === options.sdkLogLevel
  )
}

async function ensureAvatarSdk(options: UseSpatialRealAvatarOptions) {
  if (!AvatarSDK.isInitialized) {
    await AvatarSDK.initialize(options.appId, {
      characterApiBaseUrl: options.characterApiBaseUrl,
      drivingServiceMode: options.drivingServiceMode ?? DrivingServiceMode.host,
      environment: options.environment ?? Environment.intl,
      logLevel: options.sdkLogLevel,
    })
  } else if (!sameSdkConfiguration(options)) {
    throw new Error(
      'AvatarSDK is already initialized with a different configuration. Keep appId and SDK options stable across mounted SpatialReal avatar providers.',
    )
  }

  if (options.sessionToken) {
    AvatarSDK.setSessionToken(options.sessionToken)
  }

  if (options.userId) {
    AvatarSDK.setUserId(options.userId)
  }
}

function createIdleState(): SpatialRealAvatarState {
  return {
    downloadProgress: null,
    error: null,
    isConnected: false,
    isLoading: false,
    isPublishingMicrophone: false,
    micTrack: undefined,
    room: null,
    status: 'idle',
  }
}

export function useSpatialRealAvatar(
  options: UseSpatialRealAvatarOptions,
): UseSpatialRealAvatarResult {
  const {
    appId,
    avatarId,
    characterApiBaseUrl,
    connection,
    drivingServiceMode,
    enabled = true,
    environment,
    onAvatarError,
    onConnected,
    onDisconnected,
    onLoadProgress,
    onStateChange,
    playerOptions,
    publishMicrophone = false,
    sdkLogLevel,
    sessionToken,
    userId,
  } = options
  const { roomName, token, url } = connection

  const [containerElement, setContainerElement] = useState<HTMLDivElement | null>(null)
  const [containerReady, setContainerReady] = useState(false)
  const [state, setState] = useState<SpatialRealAvatarState>(createIdleState)

  const avatarViewRef = useRef<AvatarView | null>(null)
  const playerRef = useRef<AvatarPlayer | null>(null)
  const roomRef = useRef<Room | null>(null)
  const callbacksRef = useRef({
    onAvatarError,
    onConnected,
    onDisconnected,
    onLoadProgress,
    onStateChange,
    playerOptions,
  })

  useEffect(() => {
    callbacksRef.current = {
      onAvatarError,
      onConnected,
      onDisconnected,
      onLoadProgress,
      onStateChange,
      playerOptions,
    }
  }, [onAvatarError, onConnected, onDisconnected, onLoadProgress, onStateChange, playerOptions])

  const tokenSource = useMemo(
    () =>
      TokenSource.literal({
        participantToken: token,
        serverUrl: url,
      }),
    [token, url],
  )

  const baseSession = useSession(tokenSource, {
    room: state.room ?? undefined,
  })

  const updateStatus = useCallback((status: SpatialRealAvatarConnectionStatus) => {
    setState((previous) => ({
      ...previous,
      isConnected: status === 'connected',
      isLoading: status === 'initializing' || status === 'connecting',
      status,
    }))

    callbacksRef.current.onStateChange?.(status)
  }, [])

  const syncMicTrack = useCallback((room: Room | null) => {
    const publication = room?.localParticipant.getTrackPublication(Track.Source.Microphone)

    setState((previous) => ({
      ...previous,
      isPublishingMicrophone: Boolean(publication?.track),
      micTrack: publication?.track,
      room,
    }))
  }, [])

  const teardownInstance = useCallback(async (player: AvatarPlayer | null, view: AvatarView | null) => {
    if (playerRef.current === player) {
      playerRef.current = null
      roomRef.current = null
    }

    if (avatarViewRef.current === view) {
      avatarViewRef.current = null
    }

    try {
      await player?.disconnect()
    } catch {
      // Ignore teardown errors so unmounts stay predictable.
    }

    try {
      view?.dispose()
    } catch {
      // Ignore teardown errors so unmounts stay predictable.
    }
  }, [])

  const setContainerRef = useCallback((node: HTMLDivElement | null) => {
    setContainerElement(node)
    setContainerReady(node ? node.offsetWidth > 0 && node.offsetHeight > 0 : false)
  }, [])

  const startPublishingMicrophone = useCallback(async () => {
    const player = playerRef.current

    if (!player) {
      throw new Error('Avatar player is not ready yet.')
    }

    await player.startPublishing()

    const room = player.getNativeClient() as Room | null
    roomRef.current = room
    syncMicTrack(room)
  }, [syncMicTrack])

  const stopPublishingMicrophone = useCallback(async () => {
    const player = playerRef.current

    if (!player) {
      return
    }

    await player.stopPublishing()
    syncMicTrack(roomRef.current)
  }, [syncMicTrack])

  const disconnect = useCallback(async () => {
    const player = playerRef.current
    const view = avatarViewRef.current

    if (!player && !view) {
      setState(createIdleState())
      return
    }

    updateStatus('disconnecting')
    await teardownInstance(player, view)
    setState(createIdleState())
  }, [teardownInstance, updateStatus])

  const session = useMemo(
    () => ({
      ...baseSession,
      end: disconnect,
    }),
    [baseSession, disconnect],
  )

  const reconnect = useCallback(async () => {
    const player = playerRef.current

    if (!player) {
      throw new Error('Avatar player is not ready yet.')
    }

    updateStatus('connecting')

    try {
      await player.reconnect()
      const room = player.getNativeClient() as Room | null
      roomRef.current = room
      syncMicTrack(room)
      updateStatus('connected')
    } catch (error) {
      const normalizedError = toError(error, 'Failed to reconnect avatar stream.')
      setState((previous) => ({
        ...previous,
        error: normalizedError,
        isConnected: false,
        isLoading: false,
        status: 'error',
      }))
      callbacksRef.current.onAvatarError?.(normalizedError)
      callbacksRef.current.onStateChange?.('error')
      throw normalizedError
    }
  }, [syncMicTrack, updateStatus])

  useEffect(() => {
    if (!containerElement) {
      return
    }

    const markReady = () => {
      setContainerReady(containerElement.offsetWidth > 0 && containerElement.offsetHeight > 0)
    }

    const observer = new ResizeObserver(markReady)
    observer.observe(containerElement)
    const frame = requestAnimationFrame(markReady)

    return () => {
      cancelAnimationFrame(frame)
      observer.disconnect()
    }
  }, [containerElement])

  useEffect(() => {
    if (!enabled || !containerReady || !containerElement) {
      return
    }

    let cancelled = false
    let player: AvatarPlayer | null = null
    let view: AvatarView | null = null
    let connectedNotified = false

    const notifyConnected = (room: Room | null) => {
      if (connectedNotified || cancelled) {
        return
      }

      connectedNotified = true
      callbacksRef.current.onConnected?.(room)
    }

    const cleanupHandlers = () => {
      if (!player) {
        return
      }

      player.off('connected', handleConnected)
      player.off('disconnected', handleDisconnected)
      player.off('error', handleError)
      player.off('stalled', handleStalled)
    }

    const handleConnected = () => {
      if (cancelled || !player) {
        return
      }

      const room = player.getNativeClient() as Room | null
      roomRef.current = room
      syncMicTrack(room)
      updateStatus('connected')
      notifyConnected(room)
    }

    const handleDisconnected = () => {
      if (cancelled) {
        return
      }

      roomRef.current = null
      setState((previous) => ({
        ...previous,
        error: null,
        isConnected: false,
        isLoading: false,
        isPublishingMicrophone: false,
        micTrack: undefined,
        room: null,
        status: 'idle',
      }))
      callbacksRef.current.onStateChange?.('idle')
      callbacksRef.current.onDisconnected?.()
    }

    const handleError = (error: unknown) => {
      if (cancelled) {
        return
      }

      const normalizedError = toError(error, 'Failed to initialize avatar.')
      setState((previous) => ({
        ...previous,
        error: normalizedError,
        isConnected: false,
        isLoading: false,
        status: 'error',
      }))
      callbacksRef.current.onAvatarError?.(normalizedError)
      callbacksRef.current.onStateChange?.('error')
    }

    const handleStalled = async () => {
      if (cancelled || !player) {
        return
      }

      try {
        await player.reconnect()
        if (cancelled) {
          return
        }

        const room = player.getNativeClient() as Room | null
        roomRef.current = room
        syncMicTrack(room)
        updateStatus('connected')
      } catch (error) {
        handleError(toError(error, 'Avatar stream stalled and could not reconnect.'))
      }
    }

    const connectAvatar = async () => {
      updateStatus('initializing')
      setState((previous) => ({
        ...previous,
        downloadProgress: null,
        error: null,
      }))

      try {
        await ensureAvatarSdk({
          appId,
          avatarId,
          characterApiBaseUrl,
          connection: {
            roomName,
            token,
            url,
          },
          drivingServiceMode,
          environment,
          sdkLogLevel,
          sessionToken,
          userId,
        })
        if (cancelled) {
          return
        }

        const avatar = await AvatarManager.shared.load(avatarId, (progress) => {
          callbacksRef.current.onLoadProgress?.(progress)

          setState((previous) => ({
            ...previous,
            downloadProgress:
              progress.type === LoadProgress.downloading
                ? progress.progress ?? null
                : progress.type === LoadProgress.completed
                  ? 1
                  : previous.downloadProgress,
          }))
        })

        if (cancelled) {
          return
        }

        view = new AvatarView(avatar, containerElement)
        player = new AvatarPlayer(new LiveKitProvider(), view, callbacksRef.current.playerOptions)

        avatarViewRef.current = view
        playerRef.current = player

        player.on('connected', handleConnected)
        player.on('disconnected', handleDisconnected)
        player.on('error', handleError)
        player.on('stalled', handleStalled)

        updateStatus('connecting')
        await player.connect({ roomName, token, url })

        if (cancelled || !player) {
          cleanupHandlers()
          await teardownInstance(player, view)
          return
        }

        const room = player.getNativeClient() as Room | null
        roomRef.current = room
        syncMicTrack(room)
        updateStatus('connected')
        notifyConnected(room)
      } catch (error) {
        const normalizedError = toError(error, 'Failed to initialize avatar.')

        if (!cancelled) {
          setState((previous) => ({
            ...previous,
            error: normalizedError,
            isConnected: false,
            isLoading: false,
            status: 'error',
          }))
          callbacksRef.current.onAvatarError?.(normalizedError)
          callbacksRef.current.onStateChange?.('error')
        }

        cleanupHandlers()
        await teardownInstance(player, view)
      }
    }

    void connectAvatar()

    return () => {
      cancelled = true
      cleanupHandlers()
      setState(createIdleState())
      void teardownInstance(player, view)
    }
  }, [
    appId,
    avatarId,
    characterApiBaseUrl,
    containerElement,
    containerReady,
    drivingServiceMode,
    enabled,
    environment,
    sdkLogLevel,
    sessionToken,
    syncMicTrack,
    teardownInstance,
    token,
    updateStatus,
    userId,
    roomName,
    url,
  ])

  useEffect(() => {
    if (!enabled || state.status !== 'connected') {
      return
    }

    if (publishMicrophone) {
      void startPublishingMicrophone().catch((error) => {
        const normalizedError = toError(error, 'Failed to publish microphone audio.')
        setState((previous) => ({
          ...previous,
          error: normalizedError,
          isConnected: false,
          isLoading: false,
          status: 'error',
        }))
        callbacksRef.current.onAvatarError?.(normalizedError)
        callbacksRef.current.onStateChange?.('error')
      })
      return
    }

    void stopPublishingMicrophone().catch((error) => {
      const normalizedError = toError(error, 'Failed to stop microphone publishing.')
      setState((previous) => ({
        ...previous,
        error: normalizedError,
      }))
      callbacksRef.current.onAvatarError?.(normalizedError)
    })
  }, [enabled, publishMicrophone, startPublishingMicrophone, state.status, stopPublishingMicrophone])

  return {
    ...state,
    connection,
    containerRef: setContainerRef,
    disconnect,
    reconnect,
    session,
    startPublishingMicrophone,
    stopPublishingMicrophone,
  }
}

'use client'

import type { CSSProperties, HTMLAttributes, MutableRefObject, Ref } from 'react'

import { useSpatialRealAvatarContext } from './spatialreal-avatar-context'
import { cn } from '../../utils'

function assignRef<T>(ref: Ref<T | null> | undefined, value: T | null) {
  if (typeof ref === 'function') {
    ref(value)
    return
  }

  if (ref) {
    ;(ref as MutableRefObject<T | null>).current = value
  }
}

export interface SpatialRealAvatarCanvasProps extends HTMLAttributes<HTMLDivElement> {
  minHeight?: CSSProperties['minHeight']
}

export function SpatialRealAvatarCanvas({
  className,
  minHeight = 420,
  ref,
  style,
  ...props
}: SpatialRealAvatarCanvasProps & { ref?: Ref<HTMLDivElement> }) {
  const { containerRef } = useSpatialRealAvatarContext()

  return (
    <div
      {...props}
      ref={(node) => {
        if (node) {
          containerRef(node)
          assignRef(ref, node)
          return
        }

        containerRef(null)
        assignRef(ref, node)
      }}
      className={cn(
        'relative z-0 w-full overflow-hidden bg-[radial-gradient(circle_at_top,hsl(var(--primary)/0.18),transparent_34%),linear-gradient(180deg,hsl(224_53%_10%)_0%,hsl(222_47%_14%)_100%)]',
        className,
      )}
      style={{ minHeight, ...style }}
    />
  )
}

'use client'

import type { HTMLAttributes, ReactNode } from 'react'
import { AlertTriangle } from 'lucide-react'

import { useSpatialRealAvatarContext } from './spatialreal-avatar-context'
import { cn } from '../../utils'

export interface SpatialRealAvatarErrorProps extends HTMLAttributes<HTMLDivElement> {
  children?: ReactNode
}

export function SpatialRealAvatarError({ className, children, ...props }: SpatialRealAvatarErrorProps) {
  const { error, status } = useSpatialRealAvatarContext()

  if (status !== 'error' || !error) {
    return null
  }

  return (
    <div
      className={cn(
        'absolute inset-0 z-20 flex items-center justify-center bg-background/75 p-6 backdrop-blur-md',
        className,
      )}
      {...props}
    >
      {children ?? (
        <div className="max-w-sm rounded-2xl border border-destructive/30 bg-card/95 p-5 text-card-foreground shadow-xl">
          <div className="flex items-start gap-3">
            <span className="rounded-full bg-destructive/10 p-2 text-destructive">
              <AlertTriangle className="size-4" />
            </span>
            <div className="space-y-1">
              <p className="text-sm font-semibold">Avatar connection failed</p>
              <p className="text-sm text-muted-foreground">{error.message}</p>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { cva, type VariantProps } from 'class-variance-authority'
import type { HTMLAttributes } from 'react'

import { cn } from '../../utils'

const frameVariants = cva(
  'relative isolate overflow-hidden rounded-[28px] border border-border/70 bg-card/95 text-card-foreground shadow-[0_28px_90px_-40px_hsl(var(--foreground)/0.45)] backdrop-blur-sm',
  {
    variants: {
      tone: {
        default: 'bg-card/95',
        muted: 'bg-muted/60',
        ghost: 'bg-background/70',
      },
    },
    defaultVariants: {
      tone: 'default',
    },
  },
)

export interface SpatialRealAvatarFrameProps
  extends HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof frameVariants> {}

export function SpatialRealAvatarFrame({ className, tone, ...props }: SpatialRealAvatarFrameProps) {
  return <div className={cn(frameVariants({ tone }), className)} {...props} />
}

'use client'

import type { HTMLAttributes, ReactNode } from 'react'

import { useSpatialRealAvatarContext } from './spatialreal-avatar-context'
import { cn } from '../../utils'

export interface SpatialRealAvatarLoadingProps extends HTMLAttributes<HTMLDivElement> {
  children?: ReactNode
}

export function SpatialRealAvatarLoading({ className, children, ...props }: SpatialRealAvatarLoadingProps) {
  const { downloadProgress, isLoading, status } = useSpatialRealAvatarContext()
  const progress = downloadProgress !== null ? Math.max(0, Math.min(100, downloadProgress * 100)) : null

  if (!isLoading) {
    return null
  }

  return (
    <div
      className={cn(
        'absolute inset-0 z-10 flex items-center justify-center bg-background/60 p-6 backdrop-blur-md',
        className,
      )}
      {...props}
    >
      {children ?? (
        <div className="w-full max-w-xs rounded-2xl border border-border/70 bg-card/95 p-5 text-card-foreground shadow-xl">
          <div className="flex items-center gap-3">
            <div className="size-9 animate-spin rounded-full border-2 border-primary/20 border-t-primary" />
            <div>
              <p className="text-sm font-semibold">Preparing SpatialReal avatar</p>
              <p className="text-xs text-muted-foreground capitalize">{status}</p>
            </div>
          </div>

          {progress !== null ? (
            <div className="mt-4 space-y-2">
              <div
                aria-valuemax={100}
                aria-valuemin={0}
                aria-valuenow={progress}
                className="relative h-2 w-full overflow-hidden rounded-full bg-secondary/70"
                role="progressbar"
              >
                <div
                  className="h-full rounded-full bg-primary transition-[width] duration-300 ease-out"
                  style={{ width: `${progress}%` }}
                />
              </div>
              <p className="text-xs text-muted-foreground">
                {Math.round(progress)}% of avatar assets ready
              </p>
            </div>
          ) : null}
        </div>
      )}
    </div>
  )
}

'use client'

import type { HTMLAttributes } from 'react'

import { useSpatialRealAvatarContext } from './spatialreal-avatar-context'
import type { SpatialRealAvatarConnectionStatus } from '../../types/spatialreal-avatar'
import { cn } from '../../utils'

const statusLabels: Record<SpatialRealAvatarConnectionStatus, string> = {
  idle: 'Idle',
  initializing: 'Initializing',
  connecting: 'Connecting',
  connected: 'Connected',
  disconnecting: 'Disconnecting',
  error: 'Error',
}

const statusClasses: Record<SpatialRealAvatarConnectionStatus, string> = {
  idle: 'bg-secondary text-secondary-foreground',
  initializing: 'bg-secondary text-secondary-foreground',
  connecting: 'bg-secondary text-secondary-foreground',
  connected: 'bg-emerald-500/12 text-emerald-700 dark:text-emerald-300',
  disconnecting: 'bg-secondary text-secondary-foreground',
  error: 'bg-destructive/10 text-destructive',
}

export type SpatialRealAvatarStatusProps = HTMLAttributes<HTMLDivElement>

export function SpatialRealAvatarStatus({ className, ...props }: SpatialRealAvatarStatusProps) {
  const { status } = useSpatialRealAvatarContext()

  return (
    <div
      className={cn(
        'inline-flex items-center gap-2 rounded-full px-2.5 py-1 text-xs font-semibold tracking-wide shadow-sm',
        statusClasses[status],
        className,
      )}
      {...props}
    >
      <span
        aria-hidden="true"
        className={cn(
          'size-2 rounded-full',
          status === 'connected' ? 'bg-emerald-500' : status === 'error' ? 'bg-destructive' : 'bg-current/60',
        )}
      />
      <span>{statusLabels[status]}</span>
    </div>
  )
}

import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
